function v105Norm(v){return String(v||"").replace(/\s+/g,"").replace(/[()（）·,._-]/g,"").toLowerCase();}
function v105Province(v){const s=String(v||"").trim();if(V105_PROVINCE_ALIAS[s])return V105_PROVINCE_ALIAS[s];const n=v105Norm(s);for(const [k,val] of Object.entries(V105_PROVINCE_ALIAS))if(n.includes(v105Norm(k))||v105Norm(k).includes(n))return val;return s.replace(/특별자치도|특별자치시|특별시|광역시|도$/g,"");}
function v105WholeProvince(area,province){const a=v105Norm(area),p=v105Norm(province);return !a||a===p||a===v105Norm(province+"광역시")||a===v105Norm(province+"특별시")||a===v105Norm(province+"특별자치도")||a===v105Norm(province+"특별자치시")||["대구광역시","부산광역시","울산광역시","광주광역시","대전광역시","인천광역시","제주특별자치도","세종특별자치시"].some(x=>a===v105Norm(x)&&v105Province(x)===province);}
function v105FeatureCovered(f,row){const rp=v105Province(row.province),fp=f[1];if(rp&&fp!==rp)return false;const area=String(row.area||"").replace(/\(.*?\)/g,"").trim();if(v105WholeProvince(area,fp))return true;const a=v105Norm(area),n=v105Norm(f[2]);if(!a)return false;if(n===a)return true;if(n.startsWith(a))return true;if(a.startsWith(n)&&a.length-n.length<4)return true;if(a==="세종특별자치시"&&n==="세종시")return true;return false;}
function v105CoverageFeatures(tcName){const md=getMapDataSafe();const rows=(md.coverage||[]).filter(r=>r.tc===tcName);return V105_SIGUNGU.filter(f=>rows.some(r=>v105FeatureCovered(f,r)));}
function v105Project(lat,lng){lat=Number(lat);lng=Number(lng);if(!Number.isFinite(lat)||!Number.isFinite(lng))return null;return{x:V105_MAP.ox+(lng-V105_MAP.minLng)*V105_MAP.scale,y:V105_MAP.h-(V105_MAP.oy+(lat-V105_MAP.minLat)*V105_MAP.scale)};}
function v105FeatureFromAddress(address){const raw=v105Norm(address);if(!raw)return null;let province="";for(const [k,v] of Object.entries(V105_PROVINCE_ALIAS))if(raw.includes(v105Norm(k))){province=v;break;}const pool=province?V105_SIGUNGU.filter(f=>f[1]===province):V105_SIGUNGU;const sorted=pool.slice().sort((a,b)=>v105Norm(b[2]).length-v105Norm(a[2]).length);let found=sorted.find(f=>raw.includes(v105Norm(f[2])));if(found)return found;const parents=["수원시","성남시","안양시","안산시","고양시","용인시","청주시","천안시","전주시","포항시","창원시"];
for(const p of parents)if(raw.includes(v105Norm(p))){found=sorted.find(f=>v105Norm(f[2]).startsWith(v105Norm(p)));if(found)return found;}if(raw.includes("세종"))return V105_SIGUNGU.find(f=>f[1]==="세종");return null;}
function v105Point(row){const geo=v105Project(row?.lat,row?.lng);if(geo&&geo.x>-30&&geo.x<630&&geo.y>-30&&geo.y<790)return geo;const f=v105FeatureFromAddress(row?.address);if(f)return{x:f[4],y:f[5]};const x=Number(row?.x),y=Number(row?.y);if(Number.isFinite(x)&&Number.isFinite(y))return{x:x*6,y:y*(760/118)};return{x:300,y:380};}
function v105Paths(activeIds=new Set(),contextIds=null,labels=false){return V105_SIGUNGU.map(f=>{const active=activeIds.has(f[0]);const context=contextIds&&contextIds.has(f[0]);return `<path class="v105-district ${active?"active":context?"context":""}" data-sigungu="${f[0]}" d="${f[3]}" fill-rule="evenodd"><title>${esc(f[1]+" "+f[2])}</title></path>${labels&&active?`<text class="v105-area-label" x="${f[4]}" y="${f[5]}">${esc(f[2])}</text>`:""}`;}).join("");}
function v105ProvinceLabels(){return V105_PROVINCE_LABELS.map(v=>`<text class="v105-province-label" x="${v[1]}" y="${v[2]}">${v[0]}</text>`).join("");}
function v105Marker(row,kind,selected=false,showLabel=false){const p=v105Point(row),name=String(row.name||"");const cls=kind==="store"?"store":"tc";const data=kind==="store"?`data-store="${esc(name)}"`:`data-tc="${esc(name)}"`;const width=Math.max(36,Math.min(110,name.length*10+18));return `<g class="v105-marker ${cls} ${selected?"selected":""}" ${data} transform="translate(${p.x.toFixed(1)} ${p.y.toFixed(1)})"><title>${esc(name)}</title><circle class="halo" r="8.2"/><circle class="dot" r="6.4"/><circle class="inner" r="2.1"/>${showLabel?`<g class="v105-marker-label"><rect x="10" y="-10" width="${width}" height="20" rx="8"/><text x="18" y="3.2">${esc(name)}</text></g>`:""}</g>`;}
function v105Bounds(features,point){if(features.length){let x1=Infinity,y1=Infinity,x2=-Infinity,y2=-Infinity;features.forEach(f=>{const b=f[6];x1=Math.min(x1,b[0]);y1=Math.min(y1,b[1]);x2=Math.max(x2,b[2]);y2=Math.max(y2,b[3]);});let w=Math.max(100,x2-x1),h=Math.max(100,y2-y1),pad=Math.max(18,Math.min(55,Math.max(w,h)*.14));x1-=pad;y1-=pad;x2+=pad;y2+=pad;w=x2-x1;h=y2-y1;const ratio=1.25;if(w/h<ratio){const nw=h*ratio;x1-=(nw-w)/2;x2+=(nw-w)/2;}else{const nh=w/ratio;y1-=(nh-h)/2;y2+=(nh-h)/2;}return{x:Math.max(0,x1),y:Math.max(0,y1),w:Math.min(600,Math.max(120,x2-x1)),h:Math.min(760,Math.max(120,y2-y1))};}const p=point||{x:300,y:380};return{x:Math.max(0,p.x-100),y:Math.max(0,p.y-100),w:200,h:200};}
function v105Intersects(f,b){const x=f[6];return !(x[2]<b.x||x[0]>b.x+b.w||x[3]<b.y||x[1]>b.y+b.h);}
